const input = $json;

const systemPrompt = `# Rol
Eres el Strategy Agent del sistema Innexia AI Strategic Analysis Engine v5.2 Enterprise.

# Objetivo
Transformar el contexto del proyecto, el análisis de mercado y el BMC en una tesis estratégica clara.

# Instrucciones
- Usa market_analysis como input prioritario junto con el resto del contexto.
- Genera un SWOT resumido y útil.
- Define objetivos estratégicos.
- Identifica ventajas competitivas.
- Identifica factores críticos de éxito.
- Produce recomendaciones accionables.
- Usa Tavily solo si el input requiere validación externa, benchmarking, regulación, mercado, competencia, tendencias o proveedores.
- No expliques tu razonamiento.
- Devuelve únicamente JSON válido.

# Formato de salida
{
  "strategy": {
    "swot": {
      "strengths": [],
      "weaknesses": [],
      "opportunities": [],
      "threats": []
    },
    "strategic_objectives": [],
    "competitive_advantages": [],
    "critical_success_factors": [],
    "strategic_recommendations": [],
    "assumptions": []
  }
}

# Regla final
Devuelve únicamente JSON válido.`;

const userPayload = JSON.stringify(input);

const outputSchema = {
  type: "object",
  properties: {
    strategy: {
      type: "object",
      properties: {
        swot: {
          type: "object",
          properties: {
            strengths: { type: "array", items: { type: "string" } },
            weaknesses: { type: "array", items: { type: "string" } },
            opportunities: { type: "array", items: { type: "string" } },
            threats: { type: "array", items: { type: "string" } }
          },
          required: ["strengths", "weaknesses", "opportunities", "threats"]
        },
        strategic_objectives: { type: "array", items: { type: "string" } },
        competitive_advantages: { type: "array", items: { type: "string" } },
        critical_success_factors: { type: "array", items: { type: "string" } },
        strategic_recommendations: { type: "array", items: { type: "string" } },
        assumptions: { type: "array", items: { type: "string" } }
      },
      required: ["swot", "strategic_objectives", "competitive_advantages", "critical_success_factors", "strategic_recommendations", "assumptions"]
    }
  },
  required: ["strategy"]
};

return [{ json: { input, system_prompt: systemPrompt, user_payload: userPayload, output_schema: outputSchema } }];

let content = $json.text ?? $json.output ?? $json;

if (typeof content === 'string') {
  content = content.trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/```$/, '')
      .trim();
  }

  content = JSON.parse(content);
}

if (content && typeof content === 'object' && content.__structured__output__object) {
  content = content.__structured__output__object;
}

content.strategy = content.strategy || {};
content.strategy.swot = content.strategy.swot || {};
content.strategy.swot.strengths = Array.isArray(content.strategy.swot.strengths) ? content.strategy.swot.strengths : [];
content.strategy.swot.weaknesses = Array.isArray(content.strategy.swot.weaknesses) ? content.strategy.swot.weaknesses : [];
content.strategy.swot.opportunities = Array.isArray(content.strategy.swot.opportunities) ? content.strategy.swot.opportunities : [];
content.strategy.swot.threats = Array.isArray(content.strategy.swot.threats) ? content.strategy.swot.threats : [];
content.strategy.strategic_objectives = Array.isArray(content.strategy.strategic_objectives) ? content.strategy.strategic_objectives : [];
content.strategy.competitive_advantages = Array.isArray(content.strategy.competitive_advantages) ? content.strategy.competitive_advantages : [];
content.strategy.critical_success_factors = Array.isArray(content.strategy.critical_success_factors) ? content.strategy.critical_success_factors : [];
content.strategy.strategic_recommendations = Array.isArray(content.strategy.strategic_recommendations) ? content.strategy.strategic_recommendations : [];
content.strategy.assumptions = Array.isArray(content.strategy.assumptions) ? content.strategy.assumptions : [];

return [{ json: content }];

const data = $json;

if (!data.strategy || typeof data.strategy !== 'object') {
  throw new Error('strategy faltante o inválido');
}

if (!data.strategy.swot || typeof data.strategy.swot !== 'object') {
  throw new Error('strategy.swot faltante o inválido');
}

return [{ json: data }];
